import { 
  Plus, Trash2, ArrowLeft, X, Save, 
  Loader2, Search, CheckCircle2, Upload, ImageIcon, Sparkles, Database, Table as TableIcon 
} from 'lucide-react';

// --- COMPONENTE 1: GALERÍA MAESTRA (Para subir fotos masivamente) ---
const ModalGaleria = ({ onClose, cloudName, folder, preset, API_URL }) => {
  const [archivos, setArchivos] = useState([]);
  const [subiendo, setSubiendo] = useState(false);
  const [log, setLog] = useState([]);

  const subirAFondo = async (e) => {
    const files = Array.from(e.target.files);
    setSubiendo(true);
    
    for (const file of files) {
      const formData = new FormData();
      formData.append('file', file);
      formData.append('upload_preset', preset);
      formData.append('folder', folder);
      
      try {
        const res = await axios.post(`https://api.cloudinary.com/v1_1/${cloudName}/image/upload`, formData);
        
        // Guardamos en nuestra DB la relación: Nombre del archivo <-> URL de Cloudinary
        const dataImagen = {
          nombreReferencia: file.name.toLowerCase(), // Ej: "aceite natura 900.jpg"
          publicId: res.data.public_id,
          url: res.data.secure_url
        };
        
        await axios.post(`${API_URL}/api/galeria`, dataImagen);
        setLog(prev => [...prev, { name: file.name, status: 'ok' }]);
      } catch (err) {
        setLog(prev => [...prev, { name: file.name, status: 'error' }]);
      }
    }
    setSubiendo(false);
    alert("Galería actualizada");
  };

  return (
    <div style={modalOverlay}>
      <div style={{...modalContent, width: '500px'}}>
        <div style={modalHeader}>
          <h3><Database size={20}/> Galería Maestra de Fotos</h3>
          <button onClick={onClose} style={closeBtn}><X /></button>
        </div>
        <p style={subtitleStyle}>Sube aquí todas las fotos. El sistema usará el nombre del archivo para encontrarlas luego.</p>
        
        <input type="file" multiple onChange={subirAFondo} id="upload-galeria" style={{display:'none'}} />
        <label htmlFor="upload-galeria" style={dropzoneStyle}>
          {subiendo ? <Loader2 className="animate-spin" /> : <Upload />}
          <span>{subiendo ? 'Subiendo a la nube...' : 'Seleccionar fotos para la galería'}</span>
        </label>

        <div style={{maxHeight:'200px', overflowY:'auto', marginTop:'15px'}}>
          {log.map((l, i) => (
            <div key={i} style={{fontSize:'0.8rem', display:'flex', justifyContent:'space-between', padding:'4px 0', borderBottom:'1px solid #eee'}}>
              {l.name} {l.status === 'ok' ? <CheckCircle2 size={14} color="green"/> : <X size={14} color="red"/>}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

// --- COMPONENTE 2: CARGADOR DE PRODUCTOS (El "Excel" inteligente) ---
const ModalCargaExcel = ({ onClose, API_URL, localId, onComplete, cloudName }) => {
  const [filas, setFilas] = useState([{ id: Date.now(), texto: '', precio: '', stock: '', fotoSugerida: null }]);
  const [galeria, setGaleria] = useState([]);

  useEffect(() => {
    // Cargamos las referencias de fotos que guardamos antes
    axios.get(`${API_URL}/api/galeria`).then(res => setGaleria(res.data));
  }, [API_URL]);

  const buscarMatch = (texto) => {
    if (!texto || texto.length < 3) return null;
    const t = texto.toLowerCase();
    // Busca si alguna foto de la galería contiene las palabras que el usuario escribió
    return galeria.find(f => t.split(' ').every(palabra => f.nombreReferencia.includes(palabra)));
  };

  const handleChange = (id, field, value) => {
    const nuevas = filas.map(f => {
      if (f.id === id) {
        const actualizado = { ...f, [field]: value };
        if (field === 'texto') {
          actualizado.fotoSugerida = buscarMatch(value);
        }
        return actualizado;
      }
      return f;
    });
    setFilas(nuevas);
  };

  const agregarFila = () => setFilas([...filas, { id: Date.now(), texto: '', precio: '', stock: '', fotoSugerida: null }]);

  const guardarTodo = async () => {
    try {
      const promesas = filas.map(f => {
        if (!f.texto || !f.precio) return null;
        return axios.post(`${API_URL}/api/ofertas`, {
          producto: f.texto,
          precioNuevo: f.precio,
          stock: f.stock || 0,
          publicId: f.fotoSugerida ? f.fotoSugerida.publicId : 'placeholder_id',
          local: localId
        });
      });
      await Promise.all(promesas.filter(p => p !== null));
      onComplete();
      onClose();
    } catch (e) { alert("Error al guardar productos"); }
  };

  return (
    <div style={modalOverlay}>
      <div style={{...modalContent, width: '900px'}}>
        <div style={modalHeader}>
          <h3><TableIcon size={20}/> Carga Rápida de Inventario</h3>
          <button onClick={onClose} style={closeBtn}><X /></button>
        </div>
        
        <table style={{width:'100%', borderCollapse:'collapse'}}>
          <thead>
            <tr style={{textAlign:'left', color:'#64748b', fontSize:'0.8rem'}}>
              <th>FOTO ENCONTRADA</th>
              <th>NOMBRE DEL PRODUCTO (Escribe para buscar foto)</th>
              <th>PRECIO $</th>
              <th>STOCK</th>
            </tr>
          </thead>
          <tbody>
            {filas.map(f => (
              <tr key={f.id}>
                <td style={{padding:'10px'}}>
                  {f.fotoSugerida ? 
                    <img src={`https://res.cloudinary.com/${cloudName}/image/upload/w_50,h_50,c_thumb/v1/${f.fotoSugerida.publicId}`} style={tableImg} /> 
                    : <div style={{...tableImg, background:'#f1f5f9', display:'flex', alignItems:'center', justifyContent:'center'}}><ImageIcon size={16} color="#cbd5e1"/></div>
                  }
                </td>
                <td><input style={tableInput} placeholder="Ej: Aceite Natura 900" value={f.texto} onChange={e => handleChange(f.id, 'texto', e.target.value)} /></td>
                <td><input style={tableInput} type="number" placeholder="0" value={f.precio} onChange={e => handleChange(f.id, 'precio', e.target.value)} /></td>
                <td><input style={tableInput} type="number" placeholder="0" value={f.stock} onChange={e => handleChange(f.id, 'stock', e.target.value)} /></td>
              </tr>
            ))}
          </tbody>
        </table>
        
        <div style={{marginTop:'20px', display:'flex', justifyContent:'space-between'}}>
          <button onClick={agregarFila} style={btnSecondary}><Plus size={16}/> Añadir Fila</button>
          <button onClick={guardarTodo} style={btnSave}><Save size={18}/> Guardar Inventario</button>
        </div>
      </div>
    </div>
  );
};

// --- COMPONENTE PRINCIPAL ---
const GestionOfertas = () => {
  const { id: localId } = useParams();
  const [showGaleria, setShowGaleria] = useState(false);
  const [showCarga, setShowCarga] = useState(false);
  const [ofertas, setOfertas] = useState([]);
  
  const API_URL = "http://localhost:5000"; 
  const CLOUD_NAME = "dwpgncjgn";
  const PRESET = "PRODUCTOS";

  const cargarDatos = useCallback(() => {
    axios.get(`${API_URL}/api/ofertas/local/${localId}`).then(res => setOfertas(res.data));
  }, [localId]);

  useEffect(() => { cargarDatos(); }, [cargarDatos]);

  return (
    <div style={containerStyle}>
      <div style={headerStyle}>
        <h1>Panel de Control</h1>
        <div style={{display:'flex', gap:'10px'}}>
          <button onClick={() => setShowGaleria(true)} style={btnSecondary}><Database size={18}/> 1. Gestionar Galería</button>
          <button onClick={() => setShowCarga(true)} style={btnPrimary}><Sparkles size={18}/> 2. Cargar Productos</button>
        </div>
      </div>

      <div style={gridStyle}>
        {ofertas.map(o => (
          <div key={o._id} style={itemCard}>
            <img src={`https://res.cloudinary.com/${CLOUD_NAME}/image/upload/w_200/v1/${o.publicId}`} style={imageStyle} />
            <h4>{o.producto}</h4>
            <p>${o.precioNuevo}</p>
          </div>
        ))}
      </div>

      {showGaleria && <ModalGaleria API_URL={API_URL} cloudName={CLOUD_NAME} preset={PRESET} folder="GALERIA_MAESTRA" onClose={() => setShowGaleria(false)} />}
      {showCarga && <ModalCargaExcel API_URL={API_URL} localId={localId} cloudName={CLOUD_NAME} onComplete={cargarDatos} onClose={() => setShowCarga(false)} />}
    </div>
  );
};

// --- ESTILOS ---
const containerStyle = { padding: '40px', maxWidth: '1200px', margin: '0 auto', fontFamily: 'sans-serif' };
const headerStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px' };
const gridStyle = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: '20px' };
const itemCard = { background: 'white', padding: '15px', borderRadius: '15px', border: '1px solid #eee', textAlign:'center' };
const imageStyle = { width: '100%', height: '120px', objectFit: 'contain' };
const modalOverlay = { position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.7)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 2000 };
const modalContent = { background: 'white', padding: '30px', borderRadius: '20px' };
const modalHeader = { display: 'flex', justifyContent: 'space-between', marginBottom: '20px' };
const dropzoneStyle = { border: '2px dashed #ccc', padding: '40px', borderRadius: '15px', display: 'flex', flexDirection: 'column', alignItems: 'center', cursor: 'pointer' };
const tableInput = { width: '90%', padding: '10px', border: '1px solid #ddd', borderRadius: '8px' };
const tableImg = { width: '50px', height: '50px', borderRadius: '8px', objectFit: 'cover' };
const btnPrimary = { background: '#8b5cf6', color: 'white', padding: '12px 20px', border: 'none', borderRadius: '12px', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px' };
const btnSecondary = { background: '#f1f5f9', color: '#1e293b', padding: '12px 20px', border: 'none', borderRadius: '12px', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px' };
const btnSave = { background: '#0284c7', color: 'white', padding: '12px 30px', border: 'none', borderRadius: '12px', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px' };
const subtitleStyle = { color: '#64748b', fontSize: '0.9rem', marginBottom: '15px' };
const closeBtn = { background: 'none', border: 'none', cursor: 'pointer' };

export default GestionOfertas;
